  def validateQuery(query: String): ValidationResult = {
    val errors = scala.collection.mutable.ListBuffer[String]()

    if (query == null || query.trim.isEmpty) {
      return ValidationResult(isValid = false, errors = List("Query cannot be null or empty"))
    }

    val trimmedQuery = query.trim
    val upperQuery = trimmedQuery.toUpperCase

    // Check query length
    if (trimmedQuery.length > maxQueryLength) {
      errors += s"Query exceeds maximum allowed length of $maxQueryLength characters"
    }

    // Check that query starts with an allowed statement type
    val startsWithAllowed = allowedStatementTypes.exists(st => upperQuery.startsWith(st))
    if (!startsWithAllowed) {
      errors += s"Only ${allowedStatementTypes.mkString(", ")} statements are allowed"
    }

    // Check for forbidden keywords (as whole words)
    forbiddenPatterns.foreach { pattern =>
      val regex = if (pattern.contains("\\b") || pattern.contains("\\s")) {
        s"(?i)$pattern".r
      } else {
        s"(?i)\\b${java.util.regex.Pattern.quote(pattern)}\\b".r
      }
      if (regex.findFirstIn(trimmedQuery).isDefined) {
        errors += s"Forbidden SQL pattern detected: $pattern"
      }
    }

    // Check for injection patterns
    injectionPatterns.foreach { pattern =>
      val isLiteral = !pattern.contains("\\b") && !pattern.contains("\\s") && !pattern.contains("[") && !pattern.contains("(")
      if (isLiteral) {
        if (trimmedQuery.contains(pattern)) {
          errors += s"Potential SQL injection pattern detected: $pattern"
        }
      } else {
        Try(s"(?i)$pattern".r.findFirstIn(trimmedQuery)).toOption.flatten.foreach { _ =>
          errors += s"Potential SQL injection pattern detected"
        }
      }
    }

    // Check for multiple statements (semicolons not in string literals)
    if (containsMultipleStatements(trimmedQuery)) {
      errors += "Multiple SQL statements are not allowed"
    }

    // Validate that only allowed tables are referenced
    val tableValidationErrors = validateTableReferences(trimmedQuery)
    errors ++= tableValidationErrors

    ValidationResult(isValid = errors.isEmpty, errors = errors.toList)
  }

  private def containsMultipleStatements(query: String): Boolean = {
    // Simple check: look for semicolons outside of quoted strings
    var inSingleQuote = false
    var inDoubleQuote = false
    var escaped = false

    for (ch <- query) {
      if (escaped) {
        escaped = false
      } else {
        ch match {
          case '\\' => escaped = true
          case '\'' if !inDoubleQuote => inSingleQuote = !inSingleQuote
          case '"' if !inSingleQuote => inDoubleQuote = !inDoubleQuote
          case ';' if !inSingleQuote && !inDoubleQuote => return true
          case _ =>
        }
      }
    }
    false
  }

  private def validateTableReferences(query: String): List[String] = {
    val errors = scala.collection.mutable.ListBuffer[String]()

    // Parse table references using Spark's logical plan (safe parsing without execution)
    Try {
      val logicalPlan = spark.sessionState.sqlParser.parsePlan(query)
      val referencedTables = extractTableNames(logicalPlan)

      referencedTables.foreach { tableName =>
        val normalizedName = tableName.toLowerCase
        if (!allowedTables.contains(normalizedName)) {
          errors += s"Access to table '$tableName' is not permitted. Allowed tables: ${allowedTables.mkString(", ")}"
        }
      }
    } match {
      case Failure(e) =>
        errors += s"Failed to parse query: ${e.getMessage}"
      case Success(_) => // parsed successfully
    }

    errors.toList
  }

  private def extractTableNames(plan: org.apache.spark.sql.catalyst.plans.logical.LogicalPlan): Set[String] = {
    val tables = scala.collection.mutable.Set[String]()

    plan.foreach {
      case r: org.apache.spark.sql.catalyst.analysis.UnresolvedRelation =>
        tables += r.tableName
      case _ =>
    }

    // Also check subqueries
    plan.subqueries.foreach { subquery =>
      tables ++= extractTableNames(subquery)
    }

    tables.toSet
  }

  def executeQuery(userQuery: String, userId: String): QueryResult = {
    // Log the query attempt
    logQueryAttempt(userId, userQuery)

    // Step 1: Validate the query
    val validation = validateQuery(userQuery)
    if (!validation.isValid) {
      logQueryRejection(userId, userQuery, validation.errors)
      return QueryResult(
        success = false,
        data = None,
        error = Some(s"Query validation failed: ${validation.errors.mkString("; ")}"),
        rowCount = None
      )
    }

    // Step 2: Execute with resource limits
    Try {
      // Set per-query resource limits
      spark.conf.set("spark.sql.autoBroadcastJoinThreshold", "10485760") // 10MB
      spark.conf.set("spark.sql.shuffle.partitions", "200")

      val df: DataFrame = spark.sql(userQuery)

      // Enforce row limit
      val totalCount = df.count()
      val truncated = totalCount > maxResultRows
      val resultDf = if (truncated) df.limit(maxResultRows) else df

      val columns = resultDf.columns
      val rows = resultDf.collect().map { row =>
        columns.zipWithIndex.map { case (colName, idx) =>
          colName -> (if (row.isNullAt(idx)) null else row.get(idx))
        }.toMap
      }

      logQuerySuccess(userId, userQuery, totalCount)

      QueryResult(
        success = true,
        data = Some(rows),
        error = None,
        rowCount = Some(totalCount),
        truncated = truncated
      )
    } match {
      case Success(result) => result
      case Failure(exception) =>
        logQueryError(userId, userQuery, exception)
        QueryResult(
          success = false,
          data = None,
          error = Some(s"Query execution failed: ${sanitizeErrorMessage(exception.getMessage)}"),
          rowCount = None
        )
    }
