  private val maxQueriesPerMinute = 30

  def isRateLimited(userId: String): Boolean = {
    val now = System.currentTimeMillis()
    val oneMinuteAgo = now - 60000

    val timestamps = queryTimestamps.getOrElse(userId, List.empty)
    val recentTimestamps = timestamps.filter(_ > oneMinuteAgo)
    queryTimestamps.update(userId, recentTimestamps :+ now)

    recentTimestamps.size >= maxQueriesPerMinute
  }

